input.steps:
- {"title": "Load count matrix & create Seurat object", "description": "Read the gzipped count matrix, create Seurat object with standard gene/cell filters", "expected_outputs": ["Seurat object with raw counts"], "skill": "seurat-scrna", "parameters": {"input_file": "GSM4656102_sample101_counts.tab.gz", "min_cells": 3, "min_features": 200}}
- {"title": "QC metrics & visualization", "description": "Compute nFeature_RNA, nCount_RNA, percent.mt; plot distributions to inspect before filtering", "expected_outputs": ["qc_violin.png", "feature_scatter_plots.png"], "skill": "seurat-scrna"}
- {"title": "Filter cells on QC thresholds", "description": "Subset to cells with nFeature_RNA 200–2500 & percent.mt < 5%", "expected_outputs": ["Filtered Seurat object"]}
- {"title": "Normalize → FindVariableFeatures → ScaleData", "description": "LogNormalize, select 2000 HVGs, scale all genes", "expected_outputs": ["Normalized & scaled object"], "skill": "seurat-scrna"}
- {"title": "PCA & ElbowPlot", "description": "Run PCA, visualize scree plot to select number of dims (default 10)", "expected_outputs": ["elbow_plot.png"], "skill": "seurat-scrna"}
- {"title": "FindNeighbors, FindClusters, RunUMAP", "description": "Build k-NN graph, cluster with resolution=0.5, compute UMAP on 10 PCs", "expected_outputs": ["Clustered object with UMAP reduction"], "skill": "seurat-scrna"}
- {"title": "Visualize UMAP & FindAllMarkers", "description": "Plot UMAP colored by cluster; run one-vs-rest marker detection", "expected_outputs": ["umap_clusters.png", "cluster_markers.csv"], "skill": "seurat-scrna"}
- {"title": "Save results & object", "description": "Write QC summary, markers table, plots, and RDS object for later resumption", "expected_outputs": ["qc_summary.csv", "cluster_markers.csv", "pbmc.rds"]}
